import{_ as e,o as t,c as l,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"11.4 小结","description":"","frontmatter":{},"headers":[],"relativePath":"11/4.md","filePath":"11/4.md","lastUpdated":null}'),r={name:"11/4.md"};function i(n,a,s,_,d,c){return t(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="_11-4-小结" tabindex="-1">11.4 小结 <a class="header-anchor" href="#_11-4-小结" aria-label="Permalink to &quot;11.4 小结&quot;">​</a></h1><p>本章我们通过三个小节分别介绍了Go语言中如何处理错误，如何设计错误处理，然后第二小节介绍了如何通过GDB来调试程序，通过GDB我们可以单步调试、可以查看变量、修改变量、打印执行过程等，最后我们介绍了如何利用Go语言自带的轻量级框架<code>testing</code>来编写单元测试和压力测试，使用<code>go test</code>就可以方便的执行这些测试，使得我们将来代码升级修改之后很方便的进行回归测试。这一章也许对于你编写程序逻辑没有任何帮助，但是对于你编写出来的程序代码保持高质量是至关重要的，因为一个好的Web应用必定有良好的错误处理机制(错误提示的友好、可扩展性)、有好的单元测试和压力测试以保证上线之后代码能够保持良好的性能和按预期的运行。</p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一节: <a href="/11/3.html">Go怎么写测试用例</a></li><li>下一节: <a href="/12/0.html">部署与维护</a></li></ul>',4)])])}const f=e(r,[["render",i]]);export{p as __pageData,f as default};
